const axios = require('axios');

async function fetchTickers(page) {
  const url = `https://en.wikipedia.org/w/api.php?action=parse&page=${page}&prop=wikitext&format=json`;
  const res  = await axios.get(url, { headers: { 'User-Agent': 'Quantfolio/1.0 n8n-workflow' } });
  const text = res.data?.parse?.wikitext?.['*'] ?? '';
  const matches = [...text.matchAll(/\\|\\s*([A-Z]{1,5})\\s*\\|\\|/g)];
  return [...new Set(matches.map(m => m[1]))];
}

