const EXCHANGE_PRIORITY = {
  NASDAQ: 1,
  NYSE: 2,
  NYSE_ARCA: 3,
  BMV: 4,
  BIVA: 5
};

function normalizeTicker(t) {
  if (!t) return t;
  return t.replace('.MX','').replace('*','').trim();
}

// ── Nasdaq 100 ────────────────────────────────────────────────
const wikiText = wikiJson.parse.wikitext["*"];
