const nasdaq100 = [...new Set(nasdaq100Matches.map(m => m[1]))];

// ── Parser CSV ────────────────────────────────────────────────
function parseCSVFirstColumn(csv) {
  if (!csv || typeof csv !== 'string') return [];
  const lines = csv.split(/\r?\n/).slice(1);
  const tickers = [];
  for (const line of lines) {
    const cleanLine = line.trim();
    if (!cleanLine) continue;
    let ticker = cleanLine.startsWith('"')
      ? cleanLine.split('"')[1]
      : cleanLine.split(',')[0];
    if (ticker) {
      ticker = ticker.trim();
      if (/^[A-Z0-9.\-]{1,8}$/.test(ticker)) tickers.push(ticker);
    }
  }
  return tickers;
}

const sp500  = parseCSVFirstColumn(sp500csv);
const nyse   = parseCSVFirstColumn(nysecsv);
const nasdaq = parseCSVFirstColumn(nasdaqcsv);

// ── Tipos permitidos ──────────────────────────────────────────
const TIPOS_LOCALES_PERMITIDOS  = ['1', '1B', 'FI', 'FF', 'CI'];
const TIPOS_GLOBALES_PERMITIDOS = ['1A', '1I'];

// ── Parser DataBursatil local ─────────────────────────────────
function parseBMVLocal(data) {
  const items = [];
  for (const [ticker, series] of Object.entries(data)) {
    for (const [serie, info] of Object.entries(series)) {
      if (!TIPOS_LOCALES_PERMITIDOS.includes(info.tipo_valor_id)) continue;
      if (info.estatus !== 'ACTIVA') continue;
      const fullTicker = serie === '*' ? `${ticker}.MX` : `${ticker}${serie}.MX`;
      items.push({
        ticker:     fullTicker,
        baseTicker: normalizeTicker(ticker),
        exchange:   info.bolsa === 'BIVA' ? 'BIVA' : 'BMV',
        isin:       info.isin || null,
        name:       info.razon_social,
        index_name: null
      });
      break;
    }
  }
  return items;
}

// ── Parser DataBursatil global (SIC) ─────────────────────────
function parseBMVGlobal(data) {
  const items = [];
  const exchangeMap = {
    'NEW YORK STOCK EXCHANGE':              'NYSE',
    'XNYS - NEW YORK STOCK EXCHANGE, INC.': 'NYSE',
    'NASDAQ':                               'NASDAQ',
    'XNAS - NASDAQ - ALL MARKETS':          'NASDAQ',
    'LONDON STOCK EXCHANGE':                'LSE',
    'XLON - LONDON STOCK EXCHANGE':         'LSE',
    'FRANKFURT STOCK EXCHANGE':             'XETRA',
    'XETRA':                                'XETRA',
    'TOKIO STOCK EXCHANGE':                 'TSE',
    'SIX SWISS EXCHANGE':                   'SIX',
    'B Y M ESPAÑOLES':                      'BME',
  };

  for (const [ticker, series] of Object.entries(data)) {
    for (const [serie, info] of Object.entries(series)) {
      if (!TIPOS_GLOBALES_PERMITIDOS.includes(info.tipo_valor_id)) continue;
      if (info.estatus !== 'ACTIVA') continue;

      const esSIC = info.tipo_valor_descripcion?.includes('SISTEMA INTERNACIONAL');
      const esETF = info.tipo_valor_descripcion?.includes('TRAC') ||
                    info.tipo_valor_descripcion?.includes('ETF');

      items.push({
        ticker:     `${ticker}*`,
        baseTicker: normalizeTicker(ticker),
        exchange:   exchangeMap[info.bolsa] || info.bolsa,
        market:     'SIC',
        isin:       info.isin || null,
        name:       info.razon_social,
        index_name: esSIC ? 'sic_acciones' : esETF ? 'sic_etf' : 'sic'
      });
      break;
    }
  }
  return items;
}

// ── ETFs curados ──────────────────────────────────────────────
const ETF_TICKERS = [
  'SPY','QQQ','IWM','EFA','EEM','VTI','VEA','VWO','AGG','BND',
