  ...nasdaq.map(t      => ({ ticker: t, baseTicker: normalizeTicker(t), exchange: 'NASDAQ',    isin: null, name: null, index_name: null })),
];

// ── Deduplicación de listings ─────────────────────────────────
const uniqueListings = new Map();
for (const item of allItems) {
  const key = `${item.ticker}-${item.exchange}`;
  if (!uniqueListings.has(key)) {
    uniqueListings.set(key, item);
  }
}

const cleanItems = Array.from(uniqueListings.values());

// ── Map agrupado por baseTicker ───────────────────────────────
const assetMap = new Map();

for (const item of cleanItems) {
  const base = normalizeTicker(item.baseTicker || item.ticker);

  if (!assetMap.has(base)) {
    assetMap.set(base, {
      baseTicker: base,
      isin:       item.isin,
      name:       item.name,
      indices:    item.index_name ? [item.index_name] : [],
      listings:   [{
        ticker:     item.ticker,
        exchange:   item.exchange,
        is_primary: false  // ← se calcula al final
      }]
    });
  } else {
    const existing = assetMap.get(base);

    if (!existing.isin && item.isin) existing.isin = item.isin;
    if (!existing.name && item.name) existing.name = item.name;
    if (item.index_name && !existing.indices.includes(item.index_name)) {
      existing.indices.push(item.index_name);
    }

    const listingExists = existing.listings.some(
      l => l.ticker === item.ticker && l.exchange === item.exchange
    );
    if (!listingExists) {
      existing.listings.push({
        ticker:     item.ticker,
        exchange:   item.exchange,
        is_primary: false
      });
    }
  }
}

// ── Recalcula is_primary por prioridad ────────────────────────
for (const asset of assetMap.values()) {
  let bestIndex = 0;
  let bestPriority = 999;

  asset.listings.forEach((l, i) => {
    const p = EXCHANGE_PRIORITY[l.exchange] ?? 999;
    if (p < bestPriority) {
      bestPriority = p;
      bestIndex = i;
    }
  });

  asset.listings.forEach((l, i) => {
    l.is_primary = (i === bestIndex);
  });
}

// ── Modo prueba ───────────────────────────────────────────────
const TEST_MODE = true;
const TEST_LIMIT = 20;

const allAssets = Array.from(assetMap.values());
const output = TEST_MODE ? allAssets.slice(0, TEST_LIMIT) : allAssets;

// ── Output ────────────────────────────────────────────────────
const result = [];
for (const asset of output) {
  for (const listing of asset.listings) {
    result.push({
      json: {
        baseTicker: asset.baseTicker,
        isin:       asset.isin,
        name:       asset.name,
        indices:    asset.indices,
        ticker:     listing.ticker,
        exchange:   listing.exchange,
        is_primary: listing.is_primary,  // ← ya lo tienes
      }
    });
  }
}

console.log('AAPL listings:', JSON.stringify(assetMap.get('AAPL')?.listings));

return result;

