  // BMV específicos
  'Financial':                'FIN_SVC',
  'Consumer Staples':         'CONS_DEF',
  'Materials':                'BASIC_MAT',
};

const data = $json.data;

const sectorsMap = {};
data
  .filter(item => item.sector)
  .forEach(item => {
    const name = item.sector;
    if (!sectorsMap[name]) {
      sectorsMap[name] = SECTOR_CODES[name] || name.toUpperCase().replace(/\s+/g, '_');
    }
  });

const sectors = Object.entries(sectorsMap)
  .map(([name, code]) => ({ code, name }))
  .sort((a, b) => a.name.localeCompare(b.name));

return [{
  json: {
    total: sectors.length,
    sectors: sectors
  }
}];

