  ...nasdaq.map(t      => ({ ticker: t, baseTicker: normalizeTicker(t), exchange: 'NASDAQ',    isin: null, name: null, index_name: null })),
];

// ── Deduplicación de listings ─────────────────────────────────
// ← CORRECCIÓN: indices_list se inicializa correctamente desde el inicio
const uniqueListings = new Map();
for (const item of allItems) {
  const key = `${item.ticker}-${item.exchange}`;
  if (!uniqueListings.has(key)) {
    uniqueListings.set(key, {
      ...item,
      indices_list: item.index_name ? [item.index_name] : []
    });
  } else {
    const existing = uniqueListings.get(key);
    if (item.index_name && !existing.indices_list.includes(item.index_name)) {
      existing.indices_list.push(item.index_name);
    }
  }
}

// ← Ya no necesita .map() de normalización
const cleanItems = Array.from(uniqueListings.values());

// ── Map agrupado por baseTicker ───────────────────────────────
const assetMap = new Map();

for (const item of cleanItems) {
  const base = normalizeTicker(item.baseTicker || item.ticker);

  if (!assetMap.has(base)) {
    assetMap.set(base, {
      baseTicker: base,
      isin:       item.isin,
      name:       item.name,
      listings:   [{
        ticker:     item.ticker,
        exchange:   item.exchange,
        indices:    item.indices_list,
        is_primary: false
      }]
    });
  } else {
    const existing = assetMap.get(base);

    if (!existing.isin && item.isin) existing.isin = item.isin;
    if (!existing.name && item.name) existing.name = item.name;

    // ← CORRECCIÓN: busca listing por ticker únicamente, sin importar exchange
    const existingListing = existing.listings.find(l => l.ticker === item.ticker);

    if (!existingListing) {
      existing.listings.push({
        ticker:     item.ticker,
        exchange:   item.exchange,
        indices:    item.indices_list,
        is_primary: false
      });
    } else {
      // Ya existe el listing — fusiona indices
      for (const idx of item.indices_list) {
        if (!existingListing.indices.includes(idx)) {
          existingListing.indices.push(idx);
        }
      }
    }
  }
}

// ── Recalcula is_primary por prioridad ────────────────────────
for (const asset of assetMap.values()) {
  let bestIndex    = 0;
  let bestPriority = 999;

  asset.listings.forEach((l, i) => {
    const p = EXCHANGE_PRIORITY[l.exchange] ?? 999;
    if (p < bestPriority) {
      bestPriority = p;
      bestIndex    = i;
    }
  });

  asset.listings.forEach((l, i) => {
    l.is_primary = (i === bestIndex);
  });
}

