  'Materials':                'BASIC_MAT',
};

const data = $json.data;

const sectorsMap = {};
data
  .filter(item => item.sector)
  .forEach(item => {
    const name = item.sector;
    if (!sectorsMap[name]) {
      sectorsMap[name] = SECTOR_CODES[name] || name.toUpperCase().replace(/\s+/g, '_');
